"use client";

import { useState } from "react";
import type { ComponentPropsWithoutRef } from "react";

import { cn } from "@/lib/utils";

import { createCompoundContext } from "../_lib/compound";

interface PhoneInputContextValue {
  country: string;
  formatPhone: (value: string) => string;
  setCountry: (country: string) => void;
  setValue: (value: string) => void;
  value: string;
}

const { Provider, useCompoundContext } =
  createCompoundContext<PhoneInputContextValue>("PhoneInput");

export interface PhoneInputProps extends ComponentPropsWithoutRef<"div"> {
  defaultCountry?: string;
  defaultValue?: string;
  formatPhone?: (value: string) => string;
  onValueChange?: (value: string) => void;
}

function CountrySelect({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"select">) {
  const { country, setCountry } = useCompoundContext();
  return (
    <select
      value={country}
      onChange={(event) => setCountry(event.target.value)}
      className={cn(
        "rounded-md border bg-background px-3 py-2 text-sm",
        className
      )}
      {...props}
    >
      {children ?? (
        <>
          <option value="US">US +1</option>
          <option value="GB">UK +44</option>
          <option value="IN">IN +91</option>
        </>
      )}
    </select>
  );
}

function Input({ className, ...props }: ComponentPropsWithoutRef<"input">) {
  const { formatPhone, setValue, value } = useCompoundContext();
  return (
    <input
      type="tel"
      value={value}
      onChange={(event) => setValue(formatPhone(event.target.value))}
      className={cn(
        "min-w-0 flex-1 rounded-md border bg-background px-3 py-2 text-sm",
        className
      )}
      placeholder="(555) 123-4567"
      {...props}
    />
  );
}

function FormatHint({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"p">) {
  const { country } = useCompoundContext();
  return (
    <p className={cn("text-xs text-muted-foreground", className)} {...props}>
      {children ?? `Use the local phone format for ${country}.`}
    </p>
  );
}

function PhoneInputRoot({
  defaultCountry = "US",
  defaultValue = "",
  formatPhone = (value) => value.replaceAll(/[^\d+()\-\s]/g, ""),
  onValueChange,
  className,
  children,
  ...props
}: PhoneInputProps) {
  const [country, setCountry] = useState(defaultCountry);
  const [value, updateValue] = useState(defaultValue);
  const setValue = (next: string) => {
    updateValue(next);
    onValueChange?.(next);
  };
  return (
    <Provider value={{ country, formatPhone, setCountry, setValue, value }}>
      <div
        className={cn(
          "w-full space-y-2 rounded-xl border bg-card p-4 sm:p-6",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            <div className="flex gap-2">
              <CountrySelect />
              <Input />
            </div>
            <FormatHint />
          </>
        )}
      </div>
    </Provider>
  );
}

export const PhoneInput = Object.assign(PhoneInputRoot, {
  CountrySelect,
  FormatHint,
  Input,
});

"use client";

import { createContext, createElement, useContext } from "react";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export interface CompoundProviderProps<T> {
  children: ReactNode;
  value: T;
}

export const createCompoundContext = <T,>(name: string) => {
  const Context = createContext<T | null>(null);

  const Provider = ({ value, children }: CompoundProviderProps<T>) =>
    createElement(Context.Provider, { value }, children);

  const useCompoundContext = () => {
    const context = useContext(Context);

    if (!context) {
      throw new Error(`${name} subcomponents must be rendered inside ${name}.`);
    }

    return context;
  };

  return { Provider, useCompoundContext };
};

export const formatPrice = (value: number, currency = "USD") =>
  new Intl.NumberFormat("en-US", {
    currency,
    style: "currency",
  }).format(value);

export type StepStatus = "completed" | "current" | "pending";

export interface TimelineStep {
  description?: string;
  label: string;
  status?: StepStatus;
}

export const statusClasses = (status: StepStatus = "pending") =>
  cn(
    "flex h-6 w-6 items-center justify-center rounded-full text-xs",
    status === "completed" && "bg-foreground text-background",
    status === "current" && "border-2 border-foreground bg-card",
    status === "pending" && "border border-muted-foreground/40 bg-card"
  );

export interface AddressValue {
  city?: string;
  country?: string;
  state?: string;
  street?: string;
  zip?: string;
}

export interface CountryOption {
  callingCode?: string;
  code: string;
  label: string;
}

export type FieldValidator<T> = (value: T) => boolean;
